.paragraph--type--page-section .layout__region{padding-bottom:5px;}.paragraph--type--page-section .layout--twocol .layout__region--first{padding-right:5px;}.paragraph--type--page-section .layout--twocol .layout__region--second{padding-left:5px;}.paragraph--type--page-section .layout--threecol-33-34-33 .layout__region--first{padding-right:5px;}.paragraph--type--page-section .layout--threecol-33-34-33 .layout__region--second{padding-right:5px;padding-left:5px;}.paragraph--type--page-section .layout--threecol-33-34-33 .layout__region--third{padding-left:5px;}.call-out-box{padding:10px;background-repeat:no-repeat;background-position:center;background-size:cover;}.fact-box{width:100%;}.fact-box p{text-align:center;}
.text-align-left{text-align:left;}.text-align-right{text-align:right;}.text-align-center{text-align:center;}.text-align-justify{text-align:justify;}.align-left{float:left;}.align-right{float:right;}.align-center{display:block;margin-right:auto;margin-left:auto;}
.fieldgroup{padding:0;border-width:0;}
.container-inline div,.container-inline label{display:inline-block;}.container-inline .details-wrapper{display:block;}
.clearfix::after{display:table;clear:both;content:"";}
.js details:not([open]) .details-wrapper{display:none;}
.hidden{display:none;}.visually-hidden{position:absolute !important;overflow:hidden;clip:rect(1px,1px,1px,1px);width:1px;height:1px;word-wrap:normal;}.visually-hidden.focusable:active,.visually-hidden.focusable:focus-within{position:static !important;overflow:visible;clip:auto;width:auto;height:auto;}.invisible{visibility:hidden;}
.item-list__comma-list,.item-list__comma-list li{display:inline;}.item-list__comma-list{margin:0;padding:0;}.item-list__comma-list li::after{content:", ";}.item-list__comma-list li:last-child::after{content:"";}
.js .js-hide{display:none;}.js-show{display:none;}.js .js-show{display:block;}
.nowrap{white-space:nowrap;}
.position-container{position:relative;}
.reset-appearance{margin:0;padding:0;border:0 none;background:transparent;line-height:inherit;-webkit-appearance:none;appearance:none;}
.resize-none{resize:none;}.resize-vertical{min-height:2em;resize:vertical;}.resize-horizontal{max-width:100%;resize:horizontal;}.resize-both{max-width:100%;min-height:2em;resize:both;}
.system-status-counter__status-icon{display:inline-block;width:25px;height:25px;vertical-align:middle;}.system-status-counter__status-icon::before{display:block;width:100%;height:100%;content:"";background-repeat:no-repeat;background-position:center 2px;background-size:16px;}.system-status-counter__status-icon--error::before{background-image:url(/core/misc/icons/e32700/error.svg);}.system-status-counter__status-icon--warning::before{background-image:url(/core/misc/icons/e29700/warning.svg);}.system-status-counter__status-icon--checked::before{background-image:url(/core/misc/icons/73b355/check.svg);}
.system-status-report-counters__item{width:100%;margin-bottom:0.5em;padding:0.5em 0;text-align:center;white-space:nowrap;background-color:rgba(0,0,0,0.063);}@media screen and (min-width:60em){.system-status-report-counters{display:flex;flex-wrap:wrap;justify-content:space-between;}.system-status-report-counters__item--half-width{width:49%;}.system-status-report-counters__item--third-width{width:33%;}}
.system-status-general-info__item{margin-top:1em;padding:0 1em 1em;border:1px solid #ccc;}.system-status-general-info__item-title{border-bottom:1px solid #ccc;}
.tablesort{display:inline-block;width:16px;height:16px;background-size:100%;}.tablesort--asc{background-image:url(/core/misc/icons/787878/twistie-down.svg);}.tablesort--desc{background-image:url(/core/misc/icons/787878/twistie-up.svg);}
.block-abc-bins-bin-dates-lookup .abc-bins-dates-lookup-form{border:2px solid #07295A;display:flex;flex-wrap:wrap;}.block-abc-bins-bin-dates-lookup .abc-bins-dates-lookup-form:focus-within{box-shadow:0 0 0 2px #FFC40C;}.block-abc-bins-bin-dates-lookup .abc-bins-dates-lookup-form .form-item-postcode{flex:1;margin:0;}.block-abc-bins-bin-dates-lookup .abc-bins-dates-lookup-form .form-item-postcode input{border:2px solid #000;background-color:#ffffff;color:#000000;outline:none;}.block-abc-bins-bin-dates-lookup .abc-bins-dates-lookup-form .form-item-postcode input:focus-visible{outline:none;display:inline-block;}.block-abc-bins-bin-dates-lookup .abc-bins-dates-lookup-form .form-item-address{width:100%;margin:0;}.block-abc-bins-bin-dates-lookup .abc-bins-dates-lookup-form .form-submit.button{height:100%;border:none;outline:none;background-color:var(--color-blue);text-decoration:none;}.block-abc-bins-bin-dates-lookup .abc-bins-dates-lookup-form .form-submit.button:hover{color:white;background-color:#07295A;}.block-abc-bins-bin-dates-lookup .abc-bins-dates-lookup-form .form-submit.button:focus{color:#333;background-color:#FCDF1B;box-shadow:inset 0 -2px 0 #333333;}@media (min-width:992px){.block-abc-bins-bin-dates-lookup{border:2px solid #005a8a;padding:8px;border-radius:6px;margin-bottom:2em;}}.General{background-color:#CEE3A7 !important;}.Recycling{background-color:#9FCCEC !important;}.Food{background-color:#E2A757 !important;}.Glass{background-color:#ddd !important;}.well ul{padding:0;list-style-type:none;}.well li{padding:5px;border-radius:5px;display:inline;list-style-type:none;margin-right:10px;}span.beta{background-color:#f9a538;color:#fff;padding:2px;border-radius:4px;}
.status-normal{color:green;}.status-severe{color:red;}.status-issues{color:orange;}
span.ext{width:10px;height:10px;padding-right:12px;text-decoration:none;background:url(/modules/contrib/extlink/images/extlink_s.png) 2px center no-repeat;}span.mailto{width:10px;height:10px;padding-right:12px;text-decoration:none;background:url(/modules/contrib/extlink/images/extlink_s.png) -20px center no-repeat;}span.tel{width:10px;height:10px;padding-right:12px;text-decoration:none;background:url(/modules/contrib/extlink/images/extlink_s.png) -42px center no-repeat;}svg.ext{width:14px;height:14px;fill:#727272;font-weight:900;}svg.mailto,svg.tel{width:14px;height:14px;fill:#727272;}[data-extlink-placement='prepend'],[data-extlink-placement='before']{padding-right:0.2rem;}[data-extlink-placement='append'],[data-extlink-placement='after']{padding-left:0.2rem;}svg.ext path,svg.mailto path,svg.tel path{stroke:#727272;stroke-width:3;}@media print{svg.ext,svg.mailto,svg.tel,span.ext,span.mailto,span.tel{display:none;padding:0;}}.extlink i{padding-left:0.2em;}.extlink-nobreak{white-space:nowrap;}
.paragraph--unpublished{background-color:#fff4f4;}

